import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"唤潮法袍","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/3.C级/唤潮法袍.md","filePath":"4.资源分区/7.物品与装备/3.防具/3.C级/唤潮法袍.md"}'),d={name:"4.资源分区/7.物品与装备/3.防具/3.C级/唤潮法袍.md"};function l(_,a,b,i,c,p){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"唤潮法袍",tabindex:"-1"},[s("唤潮法袍 "),e("a",{class:"header-anchor",href:"#唤潮法袍","aria-label":'Permalink to "唤潮法袍"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="唤潮法袍-1" tabindex="-1">唤潮法袍 <a class="header-anchor" href="#唤潮法袍-1" aria-label="Permalink to &quot;唤潮法袍&quot;">​</a></h1><p>唤潮法袍<br> C+1000<br> 魔法本质<br> 类型：防具/轻甲<br> 这是一件通体蔚蓝色的斗篷，凝视它时，海的波纹在其上荡漾，行走时，会留下一阵海风的咸腥。<br> 由导魔特性良好的蛛丝纺织，其上的色彩是以特殊培育的水魔力富集的蓝色藻类提取而出，以海妖们特有的附魔手段为其染色，并留下了【海潮护盾】与【唤潮】两种特殊附魔。<br> 【海潮护盾】<br> 穿戴此法袍时，富集的水魔力将环绕在你的周身，使得你犹如置身大海一般，一切的攻击也都将被海潮阻拦。<br> 海水中富含的氧气将为你供应所需的生存条件，并且当你身处水流中时，你将可以自由活动，这是海赐予你的权利。<br> 法袍将为你提供10点偏斜防御，并且给与你全环境呼吸效果和在水面上可以以等同于基础移动速度进行移动的能力。<br> 【唤潮】<br> 穿戴此法袍时，富集的水魔力将在你进行攻击时为你提供海潮的助力，汹涌的海浪将吞噬你的敌人。<br> 当你进行施法攻击时，你的攻击将附带【潮湿】，这是一个c级的环境来源潮湿效果，目标以反射豁免，失败则陷入该潮湿状态一场景<br> 并且，在你进行施法攻击时，层叠的海浪将连绵不绝的冲击对方，你攻击时将额外造成传奇智力*1的多次攻击减值，并且视为拥有【余波】效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
